const approvedPosts = $('Fetch Approved Unscheduled').all().filter(p => p.json && p.json.id);
const futureScheduled = $('Fetch Future Scheduled').all().filter(p => p.json && p.json.scheduled_at);

if (approvedPosts.length === 0) {
  return [];
}

// Luxon DateTime is available globally as DateTime
let start = DateTime.now().setZone('Europe/Berlin');

// Convert future scheduled times to a Set of strings to check for collisions
const scheduledSlots = new Set(futureScheduled.map(p => {
  if (!p.json.scheduled_at) return '';
  return DateTime.fromISO(p.json.scheduled_at).setZone('Europe/Berlin').toFormat('yyyy-MM-dd HH:mm');
}).filter(Boolean));

function getNextSlot(dt) {
  let candidate = dt.set({ hour: 15, minute: 0, second: 0, millisecond: 0 });
  if (candidate <= dt) {
    candidate = candidate.plus({ days: 1 });
  }
  // Only allow Mon (1), Wed (3), Fri (5), and Sun (7) at 15:00 Berlin time
  const validDays = [1, 3, 5, 7];
  while (!validDays.includes(candidate.weekday)) {
    candidate = candidate.plus({ days: 1 });
  }
  return candidate;
}

const updates = [];
let currentPointer = start;

for (const post of approvedPosts) {
  let slot = getNextSlot(currentPointer);
  while (scheduledSlots.has(slot.toFormat('yyyy-MM-dd HH:mm'))) {
    slot = getNextSlot(slot);
  }

  updates.push({
    json: {
      id: post.json.id,
      scheduled_at: slot.toUTC().toISO(),
      timezone: 'Europe/Berlin'
    }
  });

  scheduledSlots.add(slot.toFormat('yyyy-MM-dd HH:mm'));
  currentPointer = slot;
}

return updates;
